package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithValidPathAndCharset() throws IOException {
        Path mockPath = mock(Path.class);
        Appendable mockAppendable = mock(Appendable.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        try (MockedStatic<Files> filesMockedStatic = mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8))
                    .thenReturn(new StringWriter());

            CSVFormat spyFormat = spy(csvFormat);
            doReturn(mockPrinter).when(spyFormat).print(any(Appendable.class));

            CSVPrinter result = spyFormat.print(mockPath, StandardCharsets.UTF_8);

            assertNotNull(result);
            verify(spyFormat).print(any(Appendable.class));
        }
    }

    @Test
    void testPrintThrowsIOExceptionWhenFilesNewBufferedWriterFails() throws IOException {
        Path mockPath = mock(Path.class);

        try (MockedStatic<Files> filesMockedStatic = mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8))
                    .thenThrow(new IOException("File write error"));

            IOException thrown = assertThrows(IOException.class, () -> csvFormat.print(mockPath, StandardCharsets.UTF_8));
            assertEquals("File write error", thrown.getMessage());
        }
    }
}
